import React, { useState, useCallback, useEffect } from 'react';
import VFXHeader from './components/VFXHeader';
import ImageSlot from './components/ImageSlot';
import { SynthesisStatus } from './types';
import { synthesizeImages } from './services/geminiService';

const App: React.FC = () => {
  const [imageA, setImageA] = useState<string | null>(null);
  const [imageB, setImageB] = useState<string | null>(null);
  const [status, setStatus] = useState<SynthesisStatus>(SynthesisStatus.IDLE);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loadingMessage, setLoadingMessage] = useState("Initializing Engine...");

  const loadingMessages = [
    "Locking Facial Geometry...",
    "Extracting Skeletal Pose...",
    "Mapping Lighting Environment...",
    "Analyzing Wardrobe Textures...",
    "Synthesizing Contact Points...",
    "Rendering Sub-Surface Scattering...",
    "Finalizing High-Fidelity Output..."
  ];

  useEffect(() => {
    let interval: any;
    if (status === SynthesisStatus.PROCESSING) {
      let i = 0;
      interval = setInterval(() => {
        setLoadingMessage(loadingMessages[i % loadingMessages.length]);
        i++;
      }, 2500);
    }
    return () => clearInterval(interval);
  }, [status]);

  const handleUpload = (type: 'IDENTITY' | 'POSE') => (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      if (type === 'IDENTITY') setImageA(result);
      else setImageB(result);
    };
    reader.readAsDataURL(file);
  };

  const handleSynthesize = async () => {
    if (!imageA || !imageB) return;

    // Check for API Key selection (Required for Gemini 3 Pro Image)
    // Assuming window.aistudio is available in the environment
    const hasKey = await (window as any).aistudio?.hasSelectedApiKey?.();
    if (!hasKey) {
      await (window as any).aistudio?.openSelectKey?.();
      // Assume success after prompt as per instructions
    }

    setStatus(SynthesisStatus.PROCESSING);
    setError(null);
    setResult(null);

    try {
      const generatedUrl = await synthesizeImages(imageA, imageB);
      setResult(generatedUrl);
      setStatus(SynthesisStatus.SUCCESS);
    } catch (err: any) {
      if (err.message === 'API_KEY_INVALID') {
        setError("Invalid API Key Selection. Please re-select a paid project key.");
        await (window as any).aistudio?.openSelectKey?.();
      } else {
        setError(err.message || "Synthesis Failed. Please check inputs and try again.");
      }
      setStatus(SynthesisStatus.ERROR);
    }
  };

  const reset = () => {
    setResult(null);
    setStatus(SynthesisStatus.IDLE);
    setError(null);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <VFXHeader />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 space-y-8">
        {status === SynthesisStatus.IDLE || status === SynthesisStatus.ERROR ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 lg:gap-12 animate-fadeIn">
            <div className="space-y-4">
              <ImageSlot 
                label="Image A: Identity & Environment"
                description="Lead Actor & Set Details"
                type="IDENTITY"
                image={imageA}
                onUpload={handleUpload('IDENTITY')}
                onClear={() => setImageA(null)}
              />
            </div>
            <div className="space-y-4">
              <ImageSlot 
                label="Image B: Pose & Action"
                description="Stunt Double & Props"
                type="POSE"
                image={imageB}
                onUpload={handleUpload('POSE')}
                onClear={() => setImageB(null)}
              />
            </div>
          </div>
        ) : null}

        {status === SynthesisStatus.PROCESSING && (
          <div className="flex flex-col items-center justify-center py-24 space-y-8 animate-pulse">
            <div className="w-24 h-24 relative">
              <div className="absolute inset-0 border-4 border-blue-500/20 rounded-full"></div>
              <div className="absolute inset-0 border-t-4 border-blue-500 rounded-full animate-spin"></div>
              <div className="absolute inset-4 bg-blue-500/10 rounded-full flex items-center justify-center">
                <i className="fas fa-microchip text-blue-400 text-xl"></i>
              </div>
            </div>
            <div className="text-center space-y-2">
              <h2 className="text-2xl font-bold mono text-white">{loadingMessage}</h2>
              <p className="text-blue-400/60 mono text-xs uppercase tracking-[0.2em]">Processing Multimodal Identity Map</p>
            </div>
          </div>
        )}

        {status === SynthesisStatus.SUCCESS && result && (
          <div className="max-w-4xl mx-auto space-y-6 animate-fadeIn">
            <div className="bg-white/5 rounded-3xl overflow-hidden border border-white/10 shadow-2xl">
              <div className="p-4 bg-white/5 flex justify-between items-center border-b border-white/10">
                <span className="mono text-xs text-green-400">SYNTHESIS_COMPLETE.DAT</span>
                <div className="flex space-x-2">
                  <div className="w-2 h-2 rounded-full bg-red-500/50"></div>
                  <div className="w-2 h-2 rounded-full bg-yellow-500/50"></div>
                  <div className="w-2 h-2 rounded-full bg-green-500/50"></div>
                </div>
              </div>
              <img src={result} alt="Synthesized result" className="w-full aspect-square object-cover" />
            </div>

            <div className="flex justify-center space-x-4">
              <button 
                onClick={reset}
                className="px-8 py-3 rounded-full bg-white/10 hover:bg-white/20 text-white mono text-sm transition-all border border-white/10"
              >
                New Synthesis
              </button>
              <a 
                href={result} 
                download="vfx-synthesis.png"
                className="px-8 py-3 rounded-full bg-blue-600 hover:bg-blue-500 text-white mono text-sm transition-all shadow-lg shadow-blue-500/20 flex items-center space-x-2"
              >
                <i className="fas fa-download"></i>
                <span>Export Frame</span>
              </a>
            </div>
          </div>
        )}

        {error && (
          <div className="max-w-2xl mx-auto p-6 bg-red-500/10 border border-red-500/30 rounded-2xl flex items-center space-x-4 animate-bounce-short">
            <div className="w-12 h-12 rounded-full bg-red-500/20 flex items-center justify-center flex-shrink-0">
              <i className="fas fa-exclamation-triangle text-red-500"></i>
            </div>
            <div>
              <h3 className="text-red-500 font-bold mono uppercase text-sm">Engine Error</h3>
              <p className="text-red-400/80 text-xs mt-1">{error}</p>
            </div>
          </div>
        )}
      </main>

      {status === SynthesisStatus.IDLE && (
        <footer className="p-8 flex justify-center sticky bottom-0 bg-gradient-to-t from-black via-black/90 to-transparent">
          <button
            disabled={!imageA || !imageB}
            onClick={handleSynthesize}
            className={`
              relative group overflow-hidden px-12 py-4 rounded-full font-bold mono text-sm uppercase tracking-widest transition-all
              ${imageA && imageB 
                ? 'bg-blue-600 text-white hover:scale-105 active:scale-95 shadow-[0_0_30px_rgba(59,130,246,0.3)]' 
                : 'bg-white/5 text-white/30 cursor-not-allowed border border-white/5'}
            `}
          >
            <span className="relative z-10 flex items-center space-x-3">
              <i className="fas fa-wand-magic-sparkles"></i>
              <span>Initialize Synthesis</span>
            </span>
            {imageA && imageB && (
              <div className="absolute inset-0 bg-gradient-to-r from-blue-400 to-purple-500 opacity-0 group-hover:opacity-20 transition-opacity"></div>
            )}
          </button>
        </footer>
      )}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn {
          animation: fadeIn 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
        @keyframes bounce-short {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce-short {
          animation: bounce-short 1s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default App;

