               <div className="absolute inset-0 flex items-center justify-center">
                  <i className="fas fa-heart text-pink-400 text-3xl animate-pulse"></i>
               </div>
            </div>
            <div className="text-center">
              <h2 className="text-3xl serif italic text-pink-900">{loadingMessage}</h2>
              <p className="accent text-pink-300 text-lg mt-2">Almost ready, mon chéri...</p>
            </div>
          </div>
        )}

        {status === SynthesisStatus.SUCCESS && result && (
          <div className="max-w-3xl mx-auto space-y-8 animate-fadeIn">
            <div className="bg-white p-4 rounded-[3rem] shadow-2xl border-8 border-pink-50/50 relative">
              <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-pink-100 px-6 py-2 rounded-full border-2 border-white shadow-sm">
                <span className="accent text-pink-500 font-bold">Magical Result</span>
              </div>
              <img src={result} alt="Result" className="w-full aspect-square object-cover rounded-[2rem]" />
            </div>

            <div className="flex flex-col md:flex-row justify-center items-center gap-4">
              <button 
                onClick={reset}
                className="w-full md:w-auto px-10 py-4 rounded-full bg-pink-50 text-pink-500 serif font-bold border-2 border-pink-100 hover:bg-pink-100 transition-all shadow-sm"
              >
                Create New Muse
              </button>
              <a 
                href={result} 
                download="coquette-synthesis.png"
                className="w-full md:w-auto px-10 py-4 rounded-full bg-pink-400 text-white serif font-bold hover:bg-pink-500 transition-all shadow-lg shadow-pink-200 flex items-center justify-center space-x-2"
              >
                <i className="fas fa-save"></i>
                <span>Save Portait</span>
              </a>
            </div>
          </div>
        )}

        {error && (
          <div className="max-w-xl mx-auto p-8 bg-white border-2 border-pink-100 rounded-[2rem] text-center shadow-lg animate-fadeIn">
            <i className="fas fa-heart-crack text-pink-200 text-4xl mb-4"></i>
            <h3 className="serif text-pink-900 text-xl italic mb-2">A small misfortune...</h3>
            <p className="text-pink-400 text-sm accent text-lg">{error}</p>
          </div>
        )}
      </main>

      {(status === SynthesisStatus.IDLE) && (
        <footer className="p-12 flex flex-col items-center sticky bottom-0 bg-gradient-to-t from-white via-white/80 to-transparent z-50">
          <div className="w-24 h-px bg-pink-100 mb-8"></div>
          <button
            disabled={!imageA || !imageB}
            onClick={handleSynthesize}
            className={`
              relative px-16 py-5 rounded-full serif text-lg font-bold tracking-widest transition-all overflow-hidden
              ${imageA && imageB 
                ? 'bg-pink-400 text-white hover:scale-110 shadow-[0_10px_40px_rgba(244,114,182,0.4)]' 
                : 'bg-white text-pink-100 border-2 border-pink-50 cursor-not-allowed'}
            `}
          >
            <span className="relative z-10 flex items-center space-x-4">
              <i className="fas fa-wand-magic-sparkles"></i>
              <span className="italic">Begin Synthesis</span>
            </span>
            {imageA && imageB && (
               <div className="absolute inset-0 bg-gradient-to-r from-pink-300 to-purple-400 opacity-0 hover:opacity-100 transition-opacity"></div>
            )}
          </button>
          {(!imageA || !imageB) && (
            <p className="text-[10px] text-pink-300 mt-4 uppercase tracking-[0.3em]">Please choose both images to start the magic</p>
          )}
        </footer>
      )}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(30px) scale(0.95); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        .animate-fadeIn {
          animation: fadeIn 1s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>
    </div>
  );
};

export default App;
